// Reactive Streams (Project Reactor) backpressure example
import reactor.core.publisher.Flux;

Flux.range(1, 1000)
  .log()
  .limitRate(16) // requests 16 items at a time from upstream
  .map(i -> heavyOp(i))
  .subscribe();

// In Reactor, limitRate controls request batch size so consumer isn't overwhelmed.
